    "name": "weather",
    "description": "Get weather forecast for your current location. Uses hourly forecasts up to 36 hours or daily forecasts beyond that (max 7 days).",
    "parameters": {
      "type": "object",
      "properties": {
        "hours": {
          "type": "integer",
          "minimum": 1,
          "maximum": 168,
          "description": "Timeframe in hours (1-168). Uses hourly forecasts when <= 36 hours."
        },
        "days": {
          "type": "integer",
          "minimum": 1,
          "maximum": 7,
          "description": "Timeframe in days (1-7)."
        },
        "specific_date": {
          "type": "string",
          "description": "Get weather for a specific date. Format: 'YYYY-MM-DD' or relative terms like 'today', 'tomorrow', 'monday'."
        }
      },
      "oneOf": [
        {
          "required": [
            "hours"
          ]
        },
        {
          "required": [
            "days"
          ]
        },
        {
          "required": [
            "specific_date"
          ]
        }
      ]
    }
  },
  {
    "name": "spotify_playback",
    "description": "Control Spotify playback: play/pause, track navigation, volume, search, shuffle, repeat.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "play",
            "pause",
            "next",
            "previous",
            "volume",
            "search_track",
            "search_artist",
            "status",
            "devices",
            "shuffle",
            "repeat"
          ],
          "description": "The Spotify action to perform."
        },
        "query": {
          "type": "string",
          "description": "Search query for track or artist when using search actions or 'play' with a query."
        },
        "search_type": {
          "type": "string",
          "enum": [
            "track",
            "artist"
          ],
          "default": "track",
          "description": "When using 'play' with a query, choose whether to search tracks or artists."
        },
        "volume_level": {
          "type": "integer",
          "minimum": 0,
          "maximum": 100,
          "description": "Volume level percentage (0-100) when action is 'volume'."
        },
        "shuffle_state": {
          "type": "boolean",
          "description": "For shuffle action: true enables, false disables. If omitted, toggles."
        },
        "repeat_mode": {
          "type": "string",
          "enum": [
            "off",
            "track",
            "context"
          ],
          "description": "For repeat action: 'off', 'track' (loop one song), 'context' (loop playlist). If omitted, cycles."
        }
      },
      "required": [
        "action"
      ]
    }
  },
